export const useSWRConfig = (): FullConfiguration => {
  const parentConfig = useContext(SWRConfigContext)
  const mergedConfig = useMemo(
    () => mergeObjects(defaultConfig, parentConfig),
    [parentConfig]
  )
  return mergedConfig
}

useAnimation(
  ref,
  isExiting,
  useCallback(() => {
    // Set the state to closed, which will cause the element to be unmounted.
    setExitState(state => (state === 'exiting' ? 'closed' : state));
  }, [])
);

const debounce =
    <T extends Function>(callback: T) =>
    (wait: number) => {
      clearTimeout(timer);
      timer = setTimeout(callback, wait);
    };

export const getFirstPageKey = (getKey: SWRInfiniteKeyLoader) => {
  return serialize(getKey ? getKey(0, null) : null)[0]
}

export const unstable_serialize = (getKey: SWRInfiniteKeyLoader) => {
  return INFINITE_PREFIX + getFirstPageKey(getKey)
}
